"use client";

import * as React from "react";
import {
  Badge,
  Card,
  CardContent,
  Carousel,
  CarouselContent,
  CarouselItem,
  Container,
  Img,
  TooltipProvider,
  type CarouselApi,
} from "@gunjo/ui";

/**
 * Media carousel feature, composed from @gunjo/ui display + layout components:
 *   - Carousel / CarouselContent / CarouselItem (display) — the embla-backed
 *     slider. `controls={{ navigation, dots }}` renders the Previous/Next
 *     buttons and the dot position indicator for free.
 *   - Card / CardContent (display)  — the caption block under each image.
 *   - Img (display)                 — image with built-in aspectRatio="video",
 *     object-fit, skeleton + graceful error fallback (no broken-image icon).
 *   - Badge (display)               — the category label on each slide.
 *   - Container (layout)            — centered page width.
 *
 * NOTE on TooltipProvider: the carousel's nav buttons (TooltipButton) and the
 * dots (Tooltip) render Radix tooltips and do NOT self-wrap a provider, so the
 * whole carousel must sit under a <TooltipProvider> or rendering throws
 * "`Tooltip` must be used within `TooltipProvider`". The docs don't call this
 * out — discovered from the typed source.
 */

type Slide = {
  badge: string;
  title: string;
  caption: string;
  /** background + accent for the generated SVG poster */
  bg: string;
  accent: string;
};

const SLIDES: Slide[] = [
  {
    badge: "新着",
    title: "オーロラ ヘッドホン",
    caption: "スタジオ品質のノイズキャンセリングと、40時間のバッテリー駆動。",
    bg: "#1e1b4b",
    accent: "#818cf8",
  },
  {
    badge: "編集部おすすめ",
    title: "ルーメン デスクライト",
    caption: "2700〜6500Kを無段階調光。一日の流れに寄り添う光。",
    bg: "#0f3d3e",
    accent: "#5eead4",
  },
  {
    badge: "数量限定",
    title: "ドリフト トラベルパック",
    caption: "28Lの機内持ち込みサイズ。マグネット式ですぐ開くPCスリーブ付き。",
    bg: "#3b0764",
    accent: "#f0abfc",
  },
  {
    badge: "再入荷",
    title: "パルス スマートウォッチ",
    caption: "AMOLEDディスプレイ、デュアルバンドGPS、7日間のバッテリー。",
    bg: "#431407",
    accent: "#fdba74",
  },
];

/**
 * Self-contained SVG poster as a data URI — keeps the demo offline-friendly so
 * there are no remote-image / next.config remotePatterns concerns and no
 * broken-image console errors during build/prerender.
 */
function poster({ title, bg, accent }: Slide): string {
  const svg = `<svg xmlns="http://www.w3.org/2000/svg" width="800" height="450" viewBox="0 0 800 450">
    <defs>
      <linearGradient id="g" x1="0" y1="0" x2="1" y2="1">
        <stop offset="0" stop-color="${bg}"/>
        <stop offset="1" stop-color="${accent}"/>
      </linearGradient>
    </defs>
    <rect width="800" height="450" fill="url(#g)"/>
    <circle cx="640" cy="110" r="150" fill="${accent}" fill-opacity="0.25"/>
    <circle cx="160" cy="370" r="110" fill="#ffffff" fill-opacity="0.10"/>
    <text x="48" y="408" font-family="system-ui, sans-serif" font-size="34" font-weight="700" fill="#ffffff" fill-opacity="0.92">${title}</text>
  </svg>`;
  return `data:image/svg+xml;utf8,${encodeURIComponent(svg)}`;
}

export default function CarouselPage() {
  const [api, setApi] = React.useState<CarouselApi>();
  const [current, setCurrent] = React.useState(1);
  const [count, setCount] = React.useState(SLIDES.length);

  // Mirror the embla API into a "x of N" count indicator alongside the dots.
  React.useEffect(() => {
    if (!api) return;
    setCount(api.scrollSnapList().length);
    setCurrent(api.selectedScrollSnap() + 1);
    const onSelect = () => setCurrent(api.selectedScrollSnap() + 1);
    api.on("select", onSelect);
    api.on("reInit", onSelect);
    return () => {
      api.off("select", onSelect);
      api.off("reInit", onSelect);
    };
  }, [api]);

  return (
    <TooltipProvider>
      <main className="min-h-screen bg-background py-16 text-foreground">
        <Container size="lg" className="flex flex-col gap-8">
          <header className="flex flex-col gap-1.5">
            <h1 className="text-2xl font-semibold tracking-tight">
              注目の製品
            </h1>
            <p className="text-sm text-muted-foreground">
              @gunjo/ui の Carousel で構築したメディアギャラリーです。矢印ボタン、
              ドット、または矢印キーで切り替えられます。
            </p>
          </header>

          {/* The root Carousel defaults to a fixed w-[640px]; override with
              w-full so it fills the Container. */}
          <Carousel
            className="w-full"
            opts={{ loop: true }}
            autoPlay
            autoPlayInterval={5000}
            controls={{ navigation: true, dots: true }}
            setApi={setApi}
          >
            <CarouselContent>
              {SLIDES.map((slide) => (
                <CarouselItem key={slide.title}>
                  <Card className="overflow-hidden">
                    <Img
                      src={poster(slide)}
                      alt={slide.title}
                      aspectRatio="video"
                      objectFit="cover"
                      className="h-auto w-full rounded-none"
                    />
                    <CardContent className="flex flex-col items-start gap-2 p-6">
                      <Badge variant="secondary">{slide.badge}</Badge>
                      <h2 className="text-lg font-semibold tracking-tight">
                        {slide.title}
                      </h2>
                      <p className="text-sm text-muted-foreground">
                        {slide.caption}
                      </p>
                    </CardContent>
                  </Card>
                </CarouselItem>
              ))}
            </CarouselContent>
          </Carousel>

          {/* Numeric position indicator to complement the built-in dots. */}
          <p
            className="text-center text-sm text-muted-foreground"
            aria-live="polite"
          >
            {count}枚中 {current}枚目
          </p>
        </Container>
      </main>
    </TooltipProvider>
  );
}
